dt-example.js:
// Modify the source table before initialisation
$('#example td')
	.eq(2)
	.html(
		'A really long string to demonstrate what happens when one of the cells has a long string in it'
	);

$('#example').DataTable({
	layout: {
		top: 'searchPanes'
	}
});

dt-example.js-vanilla:
// Modify the source table before initialisation
document.querySelectorAll('#example td')[2].innerHTML =
	'A really long string to demonstrate what happens when one of the cells has a long string in it';

new DataTable('#example', {
	layout: {
		top: 'searchPanes'
	}
});
